class A {
    int func(int x) {
        return x + 2;
    }
}
class B extends A {
    int func(int x) {
        return x * 2;
    }
    int func(int x, int y) {
        return func(x) + y;
    }
}
class Main {
    public static void main(String[] args) {
        B b = new B();
        int n = 3;
        int m = 1;
        while (n-- > 0) m = b.func(m, n);
        System.out.print(m);
    }
}

#include <stdio.h>

int main() {
    int arr[4] = {2, 4, 6, 8};
    int *p = arr;
    int *q = arr + 3;

    while(p < q){
        *(p+1) = *(p+1) - *p;
        p++;
    }

    printf("%d", arr[1]+arr[2]+arr[3]);
}

#include <stdio.h>

int main() {
    unsigned int n = 12345u;
    unsigned int r = 0u;
    while(n > 0) {
        r = r * 10 + n % 10;
        n /= 100;
    }
    printf("%u", r);
    return 0;
}

